    function xor(gtUint128 memory a, uint128 b) internal returns (gtUint128 memory) {
        gtUint128 memory result;

        (uint64 bHigh, uint64 bLow) = _splitUint128(b);

        result.low = xor(a.low, bLow);
        result.high = xor(a.high, bHigh);

