// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.19;

import "./IInbox.sol";

/// @title InboxUser
/// @notice Mixin that restricts selected functions to the configured {IInbox} and exposes `inbox`.
abstract contract InboxUser {
    /// @notice Cross-chain inbox used for messaging.
    IInbox public inbox;

    error OnlyInbox(address caller);

    /// @dev Reverts unless `msg.sender` is the configured inbox.
    modifier onlyInbox() {
        if (msg.sender != address(inbox)) {
            revert OnlyInbox(msg.sender);
        }
        _;
    }

    /// @notice Set the inbox contract (typically once from a constructor or initializer).
    /// @param _inbox Inbox address.
    function setInbox(address _inbox) internal {
        inbox = IInbox(_inbox);
    }
}

contracts/mpc/PodLibBase.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.19;

import "@coti-io/coti-contracts/contracts/utils/mpc/MpcCore.sol";

import "../IInbox.sol";
import "../mpccodec/MpcAbiCodec.sol";
import "./PodUser.sol";

/// @title PodLibBase
/// @notice Shared POD helpers: fee-aware two-way sends and default outbox error surfacing.
/// @dev Callers supply `totalValueWei` and `callbackFeeLocalWei`; the inbox splits into gas units. Not responsible for `tx.gasprice`.
abstract contract PodLibBase is PodUser {
    using MpcAbiCodec for MpcAbiCodec.MpcMethodCallContext;

    constructor(address initialOwner) PodUser(initialOwner) {}

    /// @dev Minimum callback slice in wei; inbox applies stricter policy from {InboxFeeManager}.
    uint256 internal constant MIN_CALLBACK_FEE_WEI = 1;

    receive() external payable {}

    /// @param totalValueWei Total native payment forwarded to `sendTwoWayMessage` (e.g. `msg.value`).
    /// @param callbackFeeLocalWei Portion of that total reserved for the callback leg; caller-estimated.
    function _sendTwoWayWithFee(
        uint256 totalValueWei,
        uint256 callbackFeeLocalWei,
        uint256 targetChainId_,
        address targetContract_,
        IInbox.MpcMethodCall memory mpcMethodCall,
        bytes4 callbackSelector_,
        bytes4 errorSelector_
    ) internal returns (bytes32) {
        require(callbackFeeLocalWei >= MIN_CALLBACK_FEE_WEI, "PodLib: callback fee min");
        require(callbackFeeLocalWei <= totalValueWei, "PodLib: callback exceeds total");
        require(address(this).balance >= totalValueWei, "PodLib: inbox fee");
        return IInbox(inbox).sendTwoWayMessage{value: totalValueWei}(
            targetChainId_,
            targetContract_,
            mpcMethodCall,
            callbackSelector_,
            errorSelector_,
            callbackFeeLocalWei
        );
    }

    /// @dev Splits stack between building `mpc` and forwarding; avoids "stack too deep" in codec helpers.
    function _forwardTwoWay(
        IInbox.MpcMethodCall memory mpc,
        bytes4 callbackSelector,
        bytes4 errorSelector,
        uint256 totalValueWei,
        uint256 callbackFeeLocalWei
    ) internal returns (bytes32) {
        return _sendTwoWayWithFee(
            totalValueWei,
            callbackFeeLocalWei,
            cotiChainId,
            mpcExecutorAddress,
            mpc,
            callbackSelector,
            errorSelector
        );
    }

    function onDefaultMpcError(bytes32 requestId) external onlyInbox {
        (uint256 code, string memory message) = inbox.getOutboxError(requestId);
        emit ErrorRemoteCall(requestId, code, message);
    }
}

contracts/mpc/PodUser.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/Ownable.sol";

import "../IInbox.sol";
import "../InboxUser.sol";

/// @title PodUser
/// @notice POD base: COTI chain ID, MPC executor address, and owner-gated {configure}.
abstract contract PodUser is InboxUser, Ownable {
    event ErrorRemoteCall(bytes32 requestId, uint256 code, string message);

    address internal mpcExecutorAddress = 0x0000000000000000000000000000000000000000;
    uint256 internal cotiChainId = 2632500;

    constructor(address initialOwner) Ownable(initialOwner) {}

    /// @dev Internal COTI routing; use {configure} from outside this contract.
    function configureCoti(address _mpcExecutorAddress, uint256 _cotiChainId) internal virtual {
        mpcExecutorAddress = _mpcExecutorAddress;
        cotiChainId = _cotiChainId;
    }

    /// @notice Owner-only: set inbox when `inbox_ != address(0)`; always updates COTI executor and chain id.
    function configure(address inbox_, address mpcExecutor_, uint256 cotiChainId_) external onlyOwner {
        if (inbox_ != address(0)) {
            setInbox(inbox_);
        }
        configureCoti(mpcExecutor_, cotiChainId_);
    }
}

